module RefModule(CLK, RST, EN, Count);
input CLK, RST, EN;
output [2:0] Count;
reg [2:0] Count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        Count <= 0;
    else if (EN) begin
        if (Count == 7)
            Count <= 0;
        else
            Count <= Count + 1;
    end
end

endmodule
